--- a/multiplier.sv
+++ b/multiplier.sv
@@ -10,7 +10,7 @@ module system(
   input [15:0] x, y,
   output [31:0] product
 );
   mult_4bit m0 (
-    .multiplicand(x[3:0]),
+    .in_a(x[3:0]),
