before_code:
module mult_4bit(
  input [3:0] in_a,
  input [3:0] in_b,
  output [7:0] out
);
  assign out = in_a * in_b;
endmodule

module system(
  input [15:0] x, y,
  output [31:0] product
);
  mult_4bit m0 (
    .multiplicand(x[3:0]),
    .in_b(y[3:0]),
    .out(product[7:0])
  );
endmodule

after_code:
module mult_4bit(
  input [3:0] in_a,
  input [3:0] in_b,
  output [7:0] out
);
  assign out = in_a * in_b;
endmodule

module system(
  input [15:0] x, y,
  output [31:0] product
);
  mult_4bit m0 (
    .in_a(x[3:0]),
    .in_b(y[3:0]),
    .out(product[7:0])
  );
endmodule
